import { Link, useNavigate } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { ArrowRight, Mail, Lock } from 'lucide-react';
import { MemoraWordmark } from '@/components/MemoraLogo';
import MemoraLogo from '@/components/MemoraLogo';
import { useState } from 'react';
import { useTheme } from '@/lib/theme';

function BgPattern() {
  return (
    <svg className="absolute inset-0 w-full h-full opacity-[0.03]" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <pattern id="login-dots" x="0" y="0" width="32" height="32" patternUnits="userSpaceOnUse">
          <circle cx="2" cy="2" r="1.5" fill="currentColor" />
        </pattern>
        <pattern id="login-grid" x="0" y="0" width="80" height="80" patternUnits="userSpaceOnUse">
          <rect width="80" height="80" fill="url(#login-dots)" />
          <rect x="0" y="0" width="80" height="80" fill="none" stroke="currentColor" strokeWidth="0.5" opacity="0.5" />
        </pattern>
      </defs>
      <rect width="100%" height="100%" fill="url(#login-grid)" />
    </svg>
  );
}

export default function LoginPage() {
  useTheme();
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setTimeout(() => navigate('/dashboard'), 800);
  };

  return (
    <div className="min-h-screen bg-background flex">
      {/* Left panel */}
      <div className="hidden lg:flex flex-1 bg-[hsl(222,47%,6%)] relative overflow-hidden items-center justify-center p-12">
        <div className="absolute top-1/3 left-1/2 -translate-x-1/2 w-[500px] h-[500px] bg-primary/15 rounded-full blur-[120px]" />
        {/* SVG background pattern */}
        <svg className="absolute inset-0 w-full h-full opacity-[0.04] text-white" xmlns="http://www.w3.org/2000/svg">
          <defs>
            <pattern id="left-hex" x="0" y="0" width="60" height="52" patternUnits="userSpaceOnUse">
              <polygon points="30,2 55,15 55,37 30,50 5,37 5,15" fill="none" stroke="currentColor" strokeWidth="0.5" />
            </pattern>
          </defs>
          <rect width="100%" height="100%" fill="url(#left-hex)" />
        </svg>
        <div className="relative text-center">
          <MemoraLogo size={64} variant="dark" className="mx-auto mb-6" />
          <h2 className="text-3xl font-extrabold text-white mb-3">Welcome back</h2>
          <p className="text-white/50 max-w-xs">Continue your study journey. Your quizzes and flashcards are waiting.</p>
          <img
            src="https://images.fillout.com/650815/btixbdasfc/generated-images/tmLUuQ9SX77nACcj4fgCYF/img_dqYtnghiShyYiaUx.jpg"
            alt="Study"
            className="mt-8 w-64 mx-auto rounded-2xl border border-white/10"
          />
        </div>
      </div>

      {/* Right form */}
      <div className="flex-1 flex items-center justify-center p-8 relative overflow-hidden">
        <BgPattern />
        {/* Accent orb */}
        <div className="absolute top-0 right-0 w-[300px] h-[300px] bg-primary/5 rounded-full blur-[100px] pointer-events-none" />

        <div className="w-full max-w-md relative">
          <Link to="/" className="mb-10 inline-block">
            <MemoraWordmark variant="light" />
          </Link>

          <h1 className="text-2xl font-extrabold text-foreground mb-1">Sign in</h1>
          <p className="text-muted-foreground text-sm mb-8 font-medium">
            Don't have an account?{' '}
            <Link to="/register" className="text-primary font-bold hover:underline">Sign up</Link>
          </p>

          <form onSubmit={handleSubmit} className="space-y-5">
            <div>
              <Label htmlFor="email" className="text-sm font-bold">Email</Label>
              <div className="relative mt-1.5">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input id="email" type="email" placeholder="you@example.com" className="pl-10" value={email} onChange={e => setEmail(e.target.value)} required />
              </div>
            </div>
            <div>
              <Label htmlFor="password" className="text-sm font-bold">Password</Label>
              <div className="relative mt-1.5">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input id="password" type="password" placeholder="Enter your password" className="pl-10" value={password} onChange={e => setPassword(e.target.value)} required />
              </div>
            </div>

            <Button type="submit" className="w-full rounded-full" disabled={loading}>
              {loading ? 'Signing in...' : 'Sign in'} {!loading && <ArrowRight className="w-4 h-4 ml-2" />}
            </Button>
          </form>

          <div className="mt-6 text-center">
            <a href="#" className="text-sm text-muted-foreground hover:text-foreground font-medium">Forgot password?</a>
          </div>
        </div>
      </div>
    </div>
  );
}

