import { Link } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Menu, X, Sun, Moon } from 'lucide-react';
import { useState } from 'react';
import { useTheme } from '@/lib/theme';
import { MemoraWordmark } from '@/components/MemoraLogo';

export default function Navbar({ variant = 'light' }: { variant?: 'light' | 'dark' }) {
  const [open, setOpen] = useState(false);
  const { theme, toggleTheme } = useTheme();
  const isDark = variant === 'dark';

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 ${isDark ? 'bg-[hsl(222,47%,6%)]/80' : 'bg-background/80'} backdrop-blur-xl border-b border-white/[0.06]`}>
      <div className="container mx-auto px-4 h-16 flex items-center justify-between">
        <Link to="/">
          <MemoraWordmark variant={isDark ? 'dark' : 'light'} />
        </Link>

        <div className="hidden md:flex items-center gap-8">
          {['Features', 'How it Works', 'Pricing', 'Blog'].map(item => (
            <a key={item} href={`#${item.toLowerCase().replace(/ /g, '-')}`} className={`text-sm font-medium ${isDark ? 'text-white/50 hover:text-white' : 'text-muted-foreground hover:text-foreground'} transition-colors`}>
              {item}
            </a>
          ))}
        </div>

        <div className="hidden md:flex items-center gap-3">
          <button onClick={toggleTheme} className={`p-2 rounded-xl ${isDark ? 'text-white/50 hover:text-white hover:bg-white/5' : 'text-muted-foreground hover:text-foreground hover:bg-muted'} transition-all`}>
            {theme === 'dark' ? <Sun className="w-4 h-4" /> : <Moon className="w-4 h-4" />}
          </button>
          <Link to="/login">
            <Button variant="ghost" size="sm" className={`rounded-xl ${isDark ? 'text-white/70 hover:text-white hover:bg-white/5' : ''}`}>Log in</Button>
