src/pages/SummaryPage.tsx.content:
import BottomNav from '@/components/dashboard/BottomNav';
import { useTheme } from '@/lib/theme';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useState, useRef } from 'react';
import { Sparkles, FileText, Copy, Check, ArrowLeft, Upload, X, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { Link } from 'react-router-dom';

const sampleSummary = `## Key Concepts

**Photosynthesis** is the process by which plants convert light energy into chemical energy.

### Light-Dependent Reactions
- Occur in the thylakoid membranes
- Water molecules are split (photolysis)
- ATP and NADPH are produced

### Calvin Cycle
- Takes place in the stroma
- CO2 is fixed into organic molecules
- Produces G3P

### Important Points
1. 6CO2 + 6H2O = C6H12O6 + 6O2
2. Chlorophyll absorbs red and blue light
3. Green light is reflected`;

export default function SummaryPage() {
  useTheme();
  const [file, setFile] = useState<File | null>(null);
  const [topic, setTopic] = useState('');
  const [summary, setSummary] = useState('');
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  const handleFileDrop = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (f) setFile(f);
  };

  const handleGenerate = () => {
    if (!file && !topic.trim()) { toast.error('Upload a file or enter a topic'); return; }
    setLoading(true);
    setTimeout(() => { setSummary(sampleSummary); setLoading(false); toast.success('Summary generated!'); }, 2000);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(summary);
    setCopied(true);
    toast.success('Copied to clipboard');
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="min-h-screen bg-background pb-24">
      <div className="max-w-lg mx-auto px-4 pt-6">
        <div className="flex items-center gap-3 mb-6">
          <Link to="/dashboard" className="w-10 h-10 rounded-full bg-muted flex items-center justify-center text-muted-foreground">
            <ArrowLeft className="w-4 h-4" />
          </Link>
          <h1 className="text-lg font-extrabold text-foreground flex-1">AI Summary</h1>
        </div>

        <div className="space-y-4">
          {/* Upload */}
          <div
            onClick={() => fileRef.current?.click()}
            className="rounded-2xl bg-card border-2 border-dashed border-border hover:border-primary/40 p-8 text-center cursor-pointer transition-colors"
          >
            <input ref={fileRef} type="file" accept=".pdf,.txt,.doc,.docx" className="hidden" onChange={handleFileDrop} />
            {file ? (
              <div className="flex items-center justify-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-primary/10 flex items-center justify-center"><FileText className="w-5 h-5 text-primary" /></div>
                <div className="text-left">
                  <p className="text-sm font-bold text-foreground">{file.name}</p>
                  <p className="text-xs text-muted-foreground">{(file.size / 1024).toFixed(1)} KB</p>
                </div>
                <button onClick={(e) => { e.stopPropagation(); setFile(null); }} className="w-8 h-8 rounded-full bg-muted flex items-center justify-center"><X className="w-4 h-4" /></button>
              </div>
            ) : (
              <>
                <div className="w-14 h-14 rounded-2xl bg-primary/10 flex items-center justify-center mx-auto mb-3"><Upload className="w-6 h-6 text-primary" /></div>
                <p className="text-sm font-bold text-foreground mb-1">Upload study material</p>
                <p className="text-xs text-muted-foreground">PDF, TXT, DOC — AI creates the summary</p>
              </>
            )}
          </div>

          <div className="flex items-center gap-3"><div className="flex-1 h-px bg-border" /><span className="text-xs font-bold text-muted-foreground">OR</span><div className="flex-1 h-px bg-border" /></div>

          <div className="rounded-2xl bg-card border border-border p-5">
            <Label className="text-xs font-bold">Topic or Subject</Label>
            <Input className="mt-1.5" placeholder="e.g. Photosynthesis, World War II" value={topic} onChange={e => setTopic(e.target.value)} />
          </div>

          <Button onClick={handleGenerate} className="w-full rounded-full gap-2" size="lg" disabled={loading}>
            {loading ? <><Loader2 className="w-4 h-4 animate-spin" /> Generating...</> : <><Sparkles className="w-4 h-4" /> Generate Summary</>}
          </Button>

          {summary ? (
            <div className="rounded-2xl bg-card border border-border p-5">
              <div className="flex items-center justify-between mb-3">
                <div className="flex items-center gap-2"><Sparkles className="w-4 h-4 text-primary" /><span className="text-xs font-bold text-foreground">AI Summary</span></div>
                <button onClick={handleCopy}>{copied ? <Check className="w-4 h-4 text-primary" /> : <Copy className="w-4 h-4 text-muted-foreground" />}</button>
              </div>
              <div className="space-y-1">
                {summary.split('\n').map((line, i) => {
                  if (line.startsWith('## ')) return <h2 key={i} className="text-sm font-extrabold mt-3 mb-1 text-foreground">{line.replace('## ', '')}</h2>;
                  if (line.startsWith('### ')) return <h3 key={i} className="text-xs font-bold mt-2 mb-0.5 text-foreground">{line.replace('### ', '')}</h3>;
                  if (line.startsWith('- ')) return <p key={i} className="text-xs text-muted-foreground ml-3 font-medium">• {line.replace('- ', '')}</p>;
                  if (line.match(/^\d\./)) return <p key={i} className="text-xs text-muted-foreground ml-3 font-medium">{line}</p>;
                  if (line.trim() === '') return <div key={i} className="h-1" />;
                  return <p key={i} className="text-xs text-muted-foreground font-medium">{line.replace(/\*\*(.*?)\*\*/g, '$1')}</p>;
                })}
              </div>
            </div>
          ) : (
            <div className="rounded-2xl bg-card border border-border p-8 text-center">
              <div className="w-12 h-12 rounded-xl bg-muted flex items-center justify-center mx-auto mb-3"><Sparkles className="w-5 h-5 text-muted-foreground" /></div>
              <p className="text-xs text-muted-foreground font-medium">Your AI summary will appear here</p>
            </div>
          )}
        </div>
      </div>
      <BottomNav />
    </div>
  );
}

